/** Returns FAQs for a tool slug, with a generic fallback if none are defined. */
export function getFAQs(slug: string): FAQ[] {
  return TOOL_FAQS[slug] ?? [
    { q: `What is the ${slug.replace(/-/g, ' ')} tool used for?`, a: 'This tool provides a free, instant browser-based utility. Click Fullscreen for the best experience. No login or installation required.' },
    { q: 'Does this tool work on mobile?', a: 'Yes. The tool is optimized for all modern browsers on desktop, tablet, and mobile devices.' },
    { q: 'Is this tool free to use?', a: 'Yes. All White Screen Online tools are completely free with no sign-up, no login, and no hidden charges.' },
  ];
}
